const raw = $input.first().json;
const d = (typeof raw.message === 'string') ? JSON.parse(raw.message) : raw;
const m = d.medicoes || {};

const estados = ['LIVRE', 'ATENCAO', 'PERIGO', 'CRITICO'];
const estadoIdx = estados.indexOf(d.estado || 'LIVRE');

return [{
  json: {
    tag:          d.tag    || 'PLT-01',
    nome:         d.nome   || 'Plataforma',
    local:        d.local  || 'FIAP-SP',
    estado:       d.estado || 'LIVRE',
    motivo:       d.motivo || 'NORMAL',
    estadoIdx:    estadoIdx,
    isAlerta:     estadoIdx >= 2,
    temperatura:  parseFloat(m.temperatura)  || 0,
    umidade:      parseFloat(m.umidade)      || 0,
    gas_pct:      parseFloat(m.gas_pct)      || 0,
    distancia_cm: parseFloat(m.distancia_cm) || 999,
    gas_alarme:   m.gas_alarme  ? 1 : 0,
    intruso:      m.intruso     ? 1 : 0,
    timestamp:    Date.now()
  }
}];

